Makefile:
USER = oben-jha

all:
	@mkdir -p /home/$(USER)/data/mariadb
	@mkdir -p /home/$(USER)/data/wordpress
	@docker compose -f srcs/docker-compose.yml up -d --build

clean:
	@docker compose -f srcs/docker-compose.yml down

fclean: clean
	@sudo rm -rf /home/$(USER)/data/mariadb/*
	@sudo rm -rf /home/$(USER)/data/wordpress/*
	@docker system prune -af --volumes

re: fclean all

.PHONY: all clean fclean re

srcs/requirements/nginx/conf/nginx.conf:
events
{
}

http
{
	include /etc/nginx/mime.types;
	default_type application/octet-stream;

	server
	{
		listen 443 ssl;
		server_name oben-jha.42.fr;
		ssl_certificate /etc/nginx/ssl/inception.crt;
		ssl_certificate_key /etc/nginx/ssl/inception.key;
		ssl_protocols  TLSv1.2 TLSv1.3;

		root /var/www/html;
		index wp-login.php index.php index.html;
		autoindex off;

		location ~\.php$
		{
			fastcgi_split_path_info ^(.+\.php)(/.+)$;
			fastcgi_pass wordpress:9000;
			include fastcgi_params;
			fastcgi_param SCRIPT_FILENAME $document_root$fastcgi_script_name;
			if (!-f $document_root$fastcgi_script_name)
			{
				return 404;
			}
			fastcgi_param PATH_INFO $fastcgi_path_info;
		}
	}
}

srcs/requirements/mariadb/tools/script.s:
#!/bin/bash
set -e

mkdir -p /run/mysqld
chown -R mysql:mysql /run/mysqld /var/lib/mysql

if [ ! -d "/var/lib/mysql/mysql" ]; then
    mysql_install_db --user=mysql --datadir=/var/lib/mysql
fi

mysqld --user=mysql --bootstrap <<EOF
FLUSH PRIVILEGES;
CREATE DATABASE IF NOT EXISTS \`$SQL_DB\`;
CREATE USER IF NOT EXISTS '$SQL_USR'@'%' IDENTIFIED BY '$SQL_PWD';
GRANT ALL PRIVILEGES ON \`$SQL_DB\`.* TO '$SQL_USR'@'%';
ALTER USER 'root'@'localhost' IDENTIFIED BY '$SQL_ROOT_PWD';
FLUSH PRIVILEGES;
EOF

exec mysqld --user=mysql --port=3306 --bind-address=0.0.0.0
